+		if ip != "192.168.1.11" {
+			t.Fatalf("unexpected ip: %s", ip)
+		}
+		return fakeClient
+	}
+
+	cmd.SetArgs([]string{})
+	cmd.SetOut(newDiscardWriter())
+	cmd.SetErr(newDiscardWriter())
+	cmd.SilenceErrors = true
+	cmd.SilenceUsage = true
+	if err := cmd.ExecuteContext(context.Background()); err != nil {
